31	/**
32	 * Internal utility used to load {@link AutoConfigurationMetadata}.
33	 *
34	 * @author Phillip Webb
35	 */
36	final class AutoConfigurationMetadataLoader {
37	
38		private static final String PATH = "META-INF/spring-autoconfigure-metadata.properties";
39	
40		private AutoConfigurationMetadataLoader() {
41		}
42	
43		static AutoConfigurationMetadata loadMetadata(ClassLoader classLoader) {
44			return loadMetadata(classLoader, PATH);
45		}
46	
47		static AutoConfigurationMetadata loadMetadata(@Nullable ClassLoader classLoader, String path) {
48			try {
49				Enumeration<URL> urls = (classLoader != null) ? classLoader.getResources(path)
50						: ClassLoader.getSystemResources(path);
51				Properties properties = new Properties();
52				while (urls.hasMoreElements()) {
53					properties.putAll(PropertiesLoaderUtils.loadProperties(new UrlResource(urls.nextElement())));
54				}
55				return loadMetadata(properties);
56			}
57			catch (IOException ex) {
58				throw new IllegalArgumentException("Unable to load @ConditionalOnClass location [" + path + "]", ex);
59			}
60		}
61	
62		static AutoConfigurationMetadata loadMetadata(Properties properties) {
63			return new PropertiesAutoConfigurationMetadata(properties);
64		}
65	
66		/**
67		 * {@link AutoConfigurationMetadata} implementation backed by a properties file.
68		 */
69		private static class PropertiesAutoConfigurationMetadata implements AutoConfigurationMetadata {
70	
71			private final Properties properties;
72	
73			PropertiesAutoConfigurationMetadata(Properties properties) {
74				this.properties = properties;
75			}
76	
77			@Override
78			public boolean wasProcessed(String className) {
79				return this.properties.containsKey(className);
80			}
81	
82			@Override
83			public @Nullable Integer getInteger(String className, String key) {
84				return getInteger(className, key, null);
85			}
86	
87			@Override
88			public @Nullable Integer getInteger(String className, String key, @Nullable Integer defaultValue) {
89				String value = get(className, key);
90				return (value != null) ? Integer.valueOf(value) : defaultValue;
91			}
92	
93			@Override
94			public @Nullable Set<String> getSet(String className, String key) {
95				return getSet(className, key, null);
96			}
97	
98			@Override
99			public @Nullable Set<String> getSet(String className, String key, @Nullable Set<String> defaultValue) {
100				String value = get(className, key);
101				return (value != null) ? StringUtils.commaDelimitedListToSet(value) : defaultValue;
102			}
103	
104			@Override
105			public @Nullable String get(String className, String key) {
106				return get(className, key, null);
107			}
108	
109			@Override
110			public @Nullable String get(String className, String key, @Nullable String defaultValue) {
111				String value = this.properties.getProperty(className + "." + key);
112				return (value != null) ? value : defaultValue;
113			}
114	
115		}
